using Microsoft.EntityFrameworkCore;
using System.Linq;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still valid because we preserved "Discriminator" in OnModelCreating.
        // Without HasDiscriminator("Discriminator"), EF Core 9 would default to "$type" and this
        // query would return zero results against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports synchronous I/O.
        // ToList() throws; use ToListAsync() instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

